"""Минимальный контракт логгера для зависимостей. Потребители должны зависеть от протокола, а не от SystemLogger."""from __future__ import annotationsfrom typing import Any, Protocolclass LoggerProtocol(Protocol):    """Минимальный контракт логгера: debug, info, warning, error, exception. Без GUI-специфики."""    def debug(self, msg: Any, *args: Any, **kwargs: Any) -> None: ...    def info(self, msg: Any, *args: Any, **kwargs: Any) -> None: ...    def warning(self, msg: Any, *args: Any, **kwargs: Any) -> None: ...    def error(self, msg: Any, *args: Any, **kwargs: Any) -> None: ...    def exception(self, msg: Any, *args: Any, **kwargs: Any) -> None: ...